var klaroConfig={elementID:'klaro',lang:'de',default:false,acceptAll:true,callback:function(manager,service){if(service==='googleMaps'){location.reload();}},translations:{de:{consentModal:{title:'Datenschutz & Cookies',description:'Wir nutzen auf dieser Website externe Dienste (wie Google Maps), um dir zusätzliche Funktionen anzubieten.',},consentNotice:{description:'Wir nutzen Cookies und Google Maps, um unsere Webseite optimal für dich zu gestalten.',learnMore:'Einstellungen anpassen',},ok:'Alles akzeptieren',decline:'Ablehnen',googleMaps:{description:'Anzeige von interaktiven Karten.',},purposes:{functional:'Funktionale Dienste',}}},services:[{name:'googleMaps',default:false,title:'Google Maps',purposes:['functional'],onAccept:(status)=>{if(status===true&&typeof window.loadGoogleMap==='function'){window.loadGoogleMap();}}}]};document.addEventListener('DOMContentLoaded',function(){function fixKlaroDialogName(){document.querySelectorAll('[role="dialog"]').forEach(function(dialog){var labelId=dialog.getAttribute('aria-labelledby');var labelEl=labelId?document.getElementById(labelId):null;if(!labelEl||!labelEl.textContent.trim()){dialog.removeAttribute('aria-labelledby');dialog.setAttribute('aria-label','Cookie-Einstellungen');}});}
var klaroObserver=new MutationObserver(fixKlaroDialogName);klaroObserver.observe(document.body,{childList:true,subtree:true});fixKlaroDialogName();});